// =============================================================================
// FVE Konfigurace — čtení z HA entit + výchozí hodnoty
// =============================================================================

// Pomocné funkce pro čtení z HA
function getHAFloat(entityId, fallback) {
    var e = global.get("homeassistant.homeAssistant.states['" + entityId + "']") || {};
    var v = parseFloat(e.state);
    return isNaN(v) ? fallback : v;
}
function getHABool(entityId, fallback) {
    var e = global.get("homeassistant.homeAssistant.states['" + entityId + "']") || {};
    if (e.state === "on") return true;
    if (e.state === "off") return false;
    return fallback;
}

const config = {
    // =====================================================================
    // BATERIE — kapacita a amortizace čteny z HA (input_number)
    // =====================================================================
    kapacita_baterie_kwh: getHAFloat("input_number.fve_kapacita_baterie", 28),
    min_soc: 20,
    max_daily_soc: 80,
    amortizace_baterie_czk_kwh: getHAFloat("input_number.fve_amortizace_baterie", 1.5),
    charge_efficiency: 0.90,           // 10% ztráta při nabíjení
    discharge_efficiency: 0.90,        // 10% ztráta při vybíjení
    charge_rate_kwh: 5,                // rychlost nabíjení ze sítě (kWh/h)
    soc_drop_normal_pct: 5,            // % pokles SOC za hodinu v NORMAL módu
    daily_consumption_kwh: 20,         // odhadovaná denní spotřeba domu (kWh)
    soc_drop_setrit_pct: 1,

    // =====================================================================
    // S֛ — limity čteny z HA (input_number)
    // =====================================================================
    max_feed_in_w: getHAFloat("input_number.fve_max_feed_in", 7600),
    max_spotreba_sit_w: getHAFloat("input_number.fve_max_spotreba_sit", 22000),
    safety_margin_w: 2000,
    charger_max_amper: 16,             // max ampéry wallboxu
    charger_faze: 3,                   // počet fází wallboxu
    sit_napeti: 230,                   // napětí sítě (V)
    jistic_a: getHAFloat("input_number.fve_jistic", 32),

    // =====================================================================
    // NABÍJENÍ AUTA
    // =====================================================================
    nabijeni_auta_forecast_kwh: 40,    // min forecast výroby (kWh) pro letní solární nabíjení
    nabijeni_auta_min_soc: 95,         // min SOC baterie pro nabíjení ze sítě (%)
    nabijeni_auta_solar_w: 4000,       // min přebytek výroby pro sluneční nabíjení (W)
    nabijeni_auta_cena_prah_vyssi: 4.3,// max cena kWh pro nabíjení ze sítě (Kč) - vyšší práh
    nabijeni_auta_cena_prah_nizsi: 3.0,// max cena kWh pro nabíjení ze sítě (Kč) - nižší práh
    nabijeni_auta_min_soc_slunce: 85,  // min SOC baterie pro povolení solárního nabíjení (%)
    nabijeni_auta_pretizeni_w: 18000,  // práh přetížení sítě při nabíjení auta (W)
    nabijeni_auta_soc_drain_prah: 95,  // SOC práh pro drain mód solárního nabíjení (%)
    nabijeni_auta_soc_drain_w: 1000,   // max odběr z baterie v drain módu při SOC>=95% (W)
    nabijeni_auta_max_sell_price: 2.5,  // max prodejní cena pro solární nabíjení (Kč/kWh) — §5.1: nad tuto cenu se nabíjení zastaví a prodává se do sítě (vyjimka: zákaz přetoků). HA entita neexistuje, hardcoded hodnota.
    nabijeni_auta_soc_charge_w: 1000,  // rezerva solaru pro nabíjení baterie při SOC<95% (W)
    nabijeni_auta_target_batt_w: 1000, // cíl nabíjení baterie při sol. nabíjení (W)
    nabijeni_auta_dead_band_w: 500,    // dead band korekce ±W (neaktivni — nahrazeno nabijeni_auta_charge_deadband_w)
    nabijeni_auta_charge_deadband_w: 300,  // v30.10: deadband kolem max_charge_w pro anti-oscilaci (W). Smycka resi pouze bW (gridW=ignoruje, vyradeni vlivu boiler/NIBE).

    // =====================================================================
    // FVE INSTALACE
    // =====================================================================
    fve_peak_kwp: 3,
    fve_azimut: 270,
    fve_sklon: 50,

    // =====================================================================
    // VICTRON MQTT
    // =====================================================================
    victron_id: "c0619ab69c71",
    victron_mqtt_prefix: "victron",

    // =====================================================================
    // SOLÁRNÍ PŘEDPOVĚĎ
    // =====================================================================
    solar_forecast_source: "VICTRON",  // "VICTRON" nebo "OPEN_METEO"

    // =====================================================================
    // CENOVÉ PRAHY
    // =====================================================================
    prah_levna_energie: 4,             // level <= prah = levná energie
    prah_draha_energie: 12,            // level >= prah = drahá energie
    prah_ultra_levna_nakup: 1.0,       // nákupní cena (Kč/kWh) pod kterou platí ultra-levný režim

    // =====================================================================
    // *** NOČNÍ REŽIM (22:00 – 04:00) ***
    // =====================================================================
    topeni_nocni_snizeni: 0.5,         // noční snížení cílové teploty (°C) — platí i pro vysoký solární den
    topeni_nocni_od: 22,               // začátek nočního režimu (hodina)
    topeni_nocni_do: 4,                // konec nočního režimu (hodina)
    topeni_nouzova_teplota: 18,        // nouzová teplota — topit i v drahých hodinách (°C)

    // =====================================================================
    // *** NÁDRŽ — MIN °C PRO OBĚH (jen Node-RED config; max nádrže = HA input_number.topeni_max_teplota_nadrze) ***
    // =====================================================================
    topeni_min_teplota_nadrze: 33,

    // =====================================================================
    // *** TOPENÍ DOMU — HYSTEREZE A PRAHY ***
    // topeni_max_teplota_patron se čte z HA (input_number)
    // =====================================================================
    topeni_bezpecny_pokles: 0.7,       // bezpečný pokles pod target (°C)
    topeni_hystereze_chlazeni: 0.3,    // hystereze ZAP chlazeni nad nastavenou teplotou (°C); §8.0 (B): ZAP pri tgtT+0.3, OFF pri tgtT
    topeni_solar_forecast_kwh: 30,     // forecast (kWh) nad kterou méně agresivní s topením
    topeni_solar_high_day_kwh: 50,     // práh pro "vysoký solární den" — NIBE defer (kWh)
    plan_aggressive_solar_day_kwh: 50, // §4.9: při vysoké denní predikci preferuj NORMAL
    plan_aggressive_soc_pct: 60,       // §4.9: min SOC pro agresivnější NORMAL chování
    plan_aggressive_remaining_solar_kwh: 0, // §4.9: min zbývající solar dnes (kWh)
    plan_auto_demand_kwh: 25,          // §4.5: odhad zítřejší/dnešní spotřeby auta (kWh) když má hlad — agresivní prodej
    plan_sell_min_tesla_soc: 65,       // §4.5 (18.6.2026): prodej i pri auto_ma_hlad=ON kdyz sensor.tesla_soc >= tento prah (%)
    plan_solar_insufficient_threshold_kwh: 30, // pod tímto forecastem dnes = „nízký solar“ pro ZP+nabíjení,
    plan_extreme_low_solar_kwh: getHAFloat("input_number.fve_plan_extreme_low_solar_kwh", 5), // §4.9.1 práh extrémně slabého dne (kWh/d)
    plan_letni_min_solar_kwh: 30,      // §4.9 LETO: pokud zitra fZ >= toto, agresivni drain (sellTarget=25%, replCost=0, minSell=0.5 Kc).
                                        // Pod timto v lete = letni extrem -> konzervativne (jako zima).
    plan_solar_sell_threshold_kwh: 6.0, // §4.5 (12.5.2026): pod timto forecastem (kWh/h) se SMI prodavat z baterie i v solar hodine.
                                        // Predchozi 1.0 byl moc nizky -> blokoval prodej v rannich drahych hodinach (h7 sell=2.52, solar 1.22 kWh).
                                        // 6.0 kWh = ~80% feed-in cap (7.6 kW) -> baterie prodava jen kdyz solar nezaplnuje cely feed-in.
                                        // Solar dominantni hodiny (>=6 kWh, typ. polodne) zustavaji blokovany pro prodej z baterie.
    topeni_solar_override_w: 8000,     // práh solárního přebytku pro NIBE bez blokace (W)
    topeni_solar_defer_margin: 0.2,    // margin pro deferral k solární výrobě (°C)
    topeni_final_solar_kwh: 20,        // zbývající solar pro aktivaci mustHeatByPrice (kWh)
    topeni_final_hours: 3,             // hodiny před koncem solaru pro mustHeatByPrice
    topeni_solar_margin_hours: 2,      // hodiny před koncem solaru přestat čekat na patrony
    topeni_zakaz_pretok_defer_max_sol_kwh: 30,   // pod timto (kWh zitra) = nizka predikce pro odlozeni NIBE do ZP
    topeni_zakaz_pretok_defer_safe_margin_extra: 0.2, // °C: o kolik nizsi podlaha nez bezpecny pokles pri cekani na ZP (sirsi defer)

    // =====================================================================
    // AUTOMATICKE PREPINANI LETO/ZIMA REZIMU (§ 19) - hardcoded literaly,
    // HA entity neexistuji. Orchestrator v fve-modes.json (alr_fn_decide).
    // =====================================================================
    topeni_auto_rezim_indoor_gap: 0.5,           // jak hluboko pod cil spusti prepnuti na zimu (°C)
    topeni_auto_rezim_indoor_min_minut: 60,      // jak dlouho musi indoor pod cilem trvat (min)
    topeni_auto_rezim_outdoor_now_zima: 12,      // max aktualni outdoor pro prepnuti na zimu (°C) - jen skutecny chlad
    topeni_auto_rezim_outdoor_max_24h: 10,       // max predpovedi venku 24h pro prepnuti na zimu (°C) - studeny front
    topeni_auto_rezim_outdoor_now_leto: 14,      // min aktualni outdoor pro prepnuti na leto (°C)
    topeni_auto_rezim_outdoor_min_48h: 10,       // min predpovedi venku 48h pro prepnuti na leto (°C)
    topeni_auto_rezim_manual_override_h: 12,     // jak dlouho respektovat rucni prepnuti uzivatele (h)
    topeni_auto_rezim_anti_flap_h: 12,           // min doba mezi dvema automatickymi prepnutimi (h)



    // =====================================================================
    // *** NIBE TEPELNÉ ČERPADLO ***
    // =====================================================================
    nibe_peak_w: 14000,                // peak odběr NIBE (W)
    nibe_cooldown_min: 3,              // min doba mezi NIBE přepnutími (min)
    nibe_est_consumption_kwh: 7.0,
    topeni_nibe_dt_per_cycle: 6,     // odhadovaná spotřeba NIBE za hodinu (kWh)

    // =====================================================================
    // *** PATRONY — max teplota z HA (input_number) ***
    // =====================================================================
    topeni_min_pretok_patron_w: 3000,  // min přebytek pro start 1. patrony (W)
    topeni_patron_faze_w: 3000,        // výkon jedné fáze patrony (W)
    topeni_min_soc_patron: 90,         // min SOC baterie pro patron ohřev (%)
    topeni_max_teplota_patron: getHAFloat("input_number.topeni_max_teplota_patron", 53),
    topeni_patron_max_grid_draw_w: 200,// max odběr ze sítě při patrony (W)
    topeni_patron_max_sell_price: 0.9,   // max prodejní cena pro patrony (Kč/kWh). HA entita neexistuje, hardcoded hodnota.
    chlazeni_nocni_hystereze_c: 0.2,    // §8.0(B v2): nesolarni/nocni hystereze chlazeni nad tgtT (°C) — max drift ktery user akceptuje
    chlazeni_levne_drift_c: 0.4,    // §8.0(B v3): v drahe nesolarni hodine + zitra velka vyroba (isDraha && bigSolTom) necha drift az ke tgtT+drift (°C), chlazeni se odsune na solarni hodiny
    chlazeni_predchlazeni_offset_c: 0.5, // predchlazeni v solarnich hodinach: chladit az na tgtT - offset (banka chladu pri prebytku)
    chlazeni_predchlazeni_min_solar_w: 2000, // min solarni prebytek pro predchlazeni pod tgtT (W)
    chlazeni_spotreba_kwh_h: 1.0,       // odhad pridavne spotreby chlazeni v nesolarni hodine (kWh/h) — rezerva v sellTarget
    sell_correction_enabled: true,     // §4.5 BUG E: zapnout sebekorekci preprodej->nocni nakup
    sell_correction_max_kwh: 5,        // strop perzistentni korekce nightCons (kWh)
    sell_correction_decay_kwh: 0.5,    // denni uvolneni korekce pri cistem dni (kWh/den)
    sell_correction_night_buy_prah_kwh: 0.3, // min nocni nakup pro detekci poruseni (kWh/h)
    prah_nevyhodneho_prodeje_kc: 0.5,    // §8.5+§11.7: pod tuto prodejní cenu (Kč/kWh) se patrony při SOC≥95% chovají jako při zákazu přetoků (force-all 3 fáze, korekce vyřazena). Vyžaduje solar ≥ topeni_patron_min_solar_w pro low-sell trigger.
    topeni_boost_max_sell_price: 2,    // max prodejní cena pro NIBE+Patrony boost (Kč/kWh)
    topeni_patron_min_solar_w: 5000,   // min solar pro patrony (W)
    topeni_patron_discharge_limit_w: 50,   // max vybíjení baterie při SOC 90-95% (W)
    topeni_patron_drain_soc_prah: 95,      // SOC práh pro drain mód patronů (%)
    topeni_patron_drain_w: 1000,           // max odběr z baterie v drain módu (W)
    topeni_patron_discharge_hyst: 3,       // hystereze fází patrony
    posledni_solarni_hodiny: 2,          // pocet poslednich solarnich hodin kde se patrony/auto NESPOUSTI (baterie na 100%)
    topeni_dump_solar_soc: 85,
    topeni_chladna_nadrz: 40,              // práh chladné nádrže pro proaktivní ohřev (°C)         // min SOC pro dump solar do NIBE/tanku při zákaz přetoků (%)

    // =========================================================================
    // *** FILTRACE BAZÉNU ***
    // =========================================================================
    filtrace_surplus_on_w: 2500,       // min přebytek pro zapnutí filtrace (W)
    filtrace_surplus_off_w: 1500,      // hystereze pro vypnutí (W)
    // Filtrace bazénu — denní limit dle TEPLOTY VODY (§10.1, §10.2). letni_rezim NENÍ vstup.
    filtrace_pool_temp_min: 2,             // HARD CUT-OFF: pod touto teplotou filtrace VŮBEC NEBĚŽÍ (°C, §10.1)
    filtrace_pool_temp_threshold_c: 10,    // přepínač studená↔teplá voda pro denní limit (°C, §10.2)
    filtrace_pool_temp_hysterese_c: 1,     // hystereze prahu studená/teplá (°C) — proti oscilaci
    filtrace_min_studena_min: 60,          // min běh při teplotě < threshold (min/den)
    filtrace_min_tepla_min: 120,           // min běh při teplotě ≥ threshold (min/den)
    filtrace_deadline_h: 23,           // deadline pro splnění minima (hodina)
    filtrace_anti_cycle_min: 10,       // anti-cycling ochrana (min)
    filtrace_soc_low: 40,             // min SOC pro grid běh (%) — pod tímto nebاet na grid
    filtrace_solar_ok_kwh: 10,
    filtrace_min_run_min: 15,        // min nepřetržitý běh filtrace (min) — zákon 10.1        // zbývající solar (kWh) = "čekej na solar"

    // =========================================================================
    // *** POOL HEATING — VYTÁPĚNÍ BAZÉNU (§11) ***
    // =========================================================================
    pool_enabled: getHABool("input_boolean.automatizovat_vytapeni_bazenu", false),  // §11.1
    pool_na_max: getHABool("input_boolean.bazen_na_max", false),                    // §11.6 pripad 3
    pool_cilova_teplota_vody: getHAFloat("input_number.pozadovana_teplota_v_bazenu", 28),  // §11.5
    pool_min_teplota_nadrz: getHAFloat("input_number.min_teplota_nadrz_bazen", 30),  // §11.3 (vypnuti ventilu)
    pool_max_teplota_nadrz: getHAFloat("input_number.max_teplota_nadrz_bazen", 60),  // §11.3 (ABSOLUTNI MAX)
    pool_ventil_start_c: 55,                // §11.3: idealni teplota nadrze pro otevreni ventilu (°C)
    pool_nibe_min_runtime_sec: 1800,        // §11.6: min dobeh NIBE bez vyjimky (s) — kompresor
    pool_nibe_solar_zere_baterii_kwh: 8,    // §11.6: solar prah, nad kterym NIBE smi zrat baterii (kWh)
    pool_nibe_plan_horizon_h: 24,           // §11.6.1: horizont planovace pro bazen_na_max (h)
    pool_nibe_zaporna_cena_threshold: 0,    // §11.6 pripad 1: prah zaporne ceny pro NIBE → bazen (Kc/kWh)
    pool_nibe_zakaz_pretoku_solar_kwh: 13,  // §11.6 pripad 2: min solar pro trigger zakaz pretoku (kWh)
    pool_nibe_w: 3500,                      // §11.6 pr. 3 (23.5.2026): odhad spotreby NIBE pro solar guard (W). NIBE bazen ohrev ~3.5 kW.
    pool_cykly_per_degree: 2,               // §11.6.1: odhad cyklu NIBE na 1°C bazenu (kalibrace)
    pool_filtrace_cooldown_min: 10,         // §11.4: filtrace po konci topeni (min)


    // =========================================================================
    // // =====================================================================
    // BLOKACE A ŠETŘENÍ
    // =====================================================================
    min_vybijeni_blokace_w: 1300,      // povinná spotřeba domu z baterie při blokaci (W)
    setrit_grid_bias_w: 150,           // grid setpoint bias v ŠETŘIT módu (W)

    // =====================================================================
    // ZÁPORNÁ NÁKUPNÍ CENA (§4.10)
    // =====================================================================
    zaporna_psp_max_w: 18000,       // §4.10 (24.5.2026 user): max cíl importu ze sítě — jistič 22 kW, rezerva 4 kW → max 18 kW
    zaporna_nibe_reserve_w: 8000,       // NIBE běží → PSP ~14 kW (NIBE peak ~14 kW, minimum flex)
    zaporna_flex_reserve_w: 4000,       // jen flex → PSP 18 kW (22-4)
    zaporna_prah_critical_w: 20000,     // arbitr PEAK nad 20 kW (jistič 22 kW, margin 2 kW)
    zaporna_prah_safe_w: 19000,         // arbitr NORMAL pod 19 kW (deadband 1 kW pod critW)
    zaporna_prah_emergency_w: 1000,     // nad critW+1kW (21 kW) → okamzite pat=0 auto=6A boj=OFF
    // OLD zaporna_nibe_reserve_w: 5000,       // rezerva PSP pri NIBE (§4.10.1)
    zaporna_buffer_cooldown_s: 30,      // §4.10.5: cooldown JEN pro směr „uvolnit zpět" (s)
    zaporna_buffer_interval_s: 1,
    // §4.11 PRODEJ PREBYTKU misto nabijeni (AUTO) — export solarniho prebytku do site,
    // kdyz je nocni rezerva nabita a ulozeni dalsiho prebytku nema hodnotu (levny budouci nakup) nebo je baterie plna.
    prodej_misto_nabijeni_enabled: true,    // master prepinac AUTO exportu prebytku
    min_export_advantage_czk: 0.3,          // min vyhoda exportu ted vs ulozeni (Kc/kWh)
    prodej_misto_nabijeni_buffer_soc: 5,    // rezerva nad sellTarget, ktera se nabije driv nez se zacne exportovat (%)       // §4.10.5: frekvence centrálního arbitra (s) — bylo 5, pak 2, na 1 s per pozadavek 4.6.2026
    zaporna_psp_boost_w: 2000,          // §4.10.5: o kolik snížit PSP při peaku (Victron pak aktivuje PowerAssist)
    zaporna_peak_sustain_ticks: 2,      // §4.10.5: kolik tiku peaku NEZ krátíme spotřebiče (baterie absorbuje)
    zaporna_bat_max_discharge_w: 12000, // §4.10.5: odhad max vybití baterie (PowerAssist buffer)
    zaporna_min_solar_passthrough_w: 5000,

    // =====================================================================
    // HYSTEREZE SPOTŘEBIČŮ
    // =====================================================================
    hystereze_zapnuti_w: 500,
    hystereze_vypnuti_w: 200,

    // =====================================================================
    // PLÁNOVÁNÍ
    // =====================================================================
    plan_interval_min: 1,              // interval aktualizace plánu (min)
    plan_horizon_hours: 12,            // horizont plánování (hodiny)

    // =====================================================================
    // BALANCOVÁNÍ
    // =====================================================================
    balancing_force_stop_hours: 3,
    balancing_interval_days: 30,
    balancing_min_solar_kwh: 3,
    balancing_grid_reserve_w: 1000,

    // =====================================================================
    // NOČNÍ REZERVA
    // =====================================================================
    night_target_soc_margin: 5,        // margin nad minSOC pro noční cíl (%)
    night_reserve_kwh: 10,             // rezerva na noční spotřebu (kWh)

    // =====================================================================
    // CENOVÁ ARBITRÁŽ — boolean z HA (input_boolean)
    // =====================================================================
    min_arbitrage_profit_czk: 3,
    min_sell_profit_czk: 3,
    prodej_z_baterie_enabled: getHABool("input_boolean.fve_prodej_z_baterie", true),
    blokace_vybijeni: getHABool("input_boolean.fve_blokace_vybijeni", false),

    // =====================================================================
    // MANUÁLNÍ MÓD — z HA (input_select)
    // =====================================================================
    manual_mod: (function() {
        var modeMap = {
            "\u{1F916} Automaticky": "auto",
            "\u{1F7E2} Normální provoz": "normal",
            "\u{1F7E1} Šetřit baterii": "setrit",
            "\u{1F535} Nabíjet ze sítě": "nabijet_ze_site",
            "\u{1F534} Prodávat do sítě": "prodavat",
            "\u{1F7E3} Zákaz přetoků": "zakaz_pretoku",
            "\u26A1 Balancování baterie": "Balancování"
        };
        var e = global.get("homeassistant.homeAssistant.states['input_select.fve_manual_mod']") || {};
        return modeMap[e.state] || "auto";
    })(),

    // =====================================================================
    // AUTOMATIZACE + LETNÍ REŽIM — z HA (input_boolean)
    // =====================================================================
    automatizace_enabled: getHABool("input_boolean.fve_automatizace", true),
    letni_rezim: getHABool("input_boolean.letni_rezim", false),

    // =====================================================================
    // MÓDY
    // =====================================================================
    mody: {
        NORMAL: "normal",
        SETRIT: "setrit",
        NABIJET_ZE_SITE: "nabijet_ze_site",
        PRODAVAT: "prodavat",
        ZAKAZ_PRETOKU: "zakaz_pretoku",
        BALANCOVANI: "Balancování"
    },

    // =====================================================================
    // PRIORITA SPOTŘEBIČŮ (nižší = vyšší priorita)
    // =====================================================================
    priority: {
        tepelne_cerpadlo: 1,
        bojler: 2,
        baterie_nabijeni: 3,
        auto_nabijeni: 4,
        ostatni: 5
    },

    // =====================================================================
    // RYCHLE NABIJENI AUTA v25.0 (priorita #1)
    // =====================================================================
    rychle_nabit_deadline_h: 6 // max delka rychle rezimu (h) - po deadline boolean turn_off
};

// Uložit do global kontextu
global.set("fve_config", config);

// Uložit jednotlivé hodnoty pro zpětnou kompatibilitu
global.set("max_spotreba_sit", config.max_spotreba_sit_w);
global.set("forecast_vyroba_dnes", 0);
global.set("forecast_vyroba_zitra", 0);

msg.payload = config;
msg.topic = "fve/config";

node.status({fill: "green", shape: "dot", text: "Config OK (" + config.kapacita_baterie_kwh + "kWh, " + (config.letni_rezim ? "LÉTO" : "ZIMA") + ")"});

return msg;

// Zpracování cenových dat z databáze - aktualizace každou minutu
// Deduplikace: pokud tabulka obsahuje data z více dní,
// zachováme poslední (nejaktuálnější) záznam pro každou hodinu
const prices = msg.payload || [];
const config = global.get("fve_config") || {};
const rezim = config.rezim_casu || "hodina";

const now = new Date();
const currentHour = now.getHours();
const currentMinute = now.getMinutes();
const currentQuarter = Math.floor(currentMinute / 15);

// Deduplikace po hodinách - pozdější záznamy přepíší starší
var priceMap = {};
for (var i = 0; i < prices.length; i++) {
    var row = prices[i];
    var key = String(row.hour);
    if (rezim === "ctvrthodina" && row.minute !== undefined) {
        key = row.hour + "_" + row.minute;
    }
    priceMap[key] = row;
}
var dedupedPrices = [];
var keys = Object.keys(priceMap);
for (var k = 0; k < keys.length; k++) {
    dedupedPrices.push(priceMap[keys[k]]);
}

// Najít aktuální cenu
let currentPrice = null;
let priceLevel = 5; // default střední

for (const row of dedupedPrices) {
    if (row.hour === currentHour) {
        if (rezim === "ctvrthodina") {
            if (row.minute === currentQuarter * 15) {
                currentPrice = {
                    buy: row.priceCZKquarterBuy,
                    sell: row.priceCZKquarterProd,
                    levelBuy: row.levelCheapestQuarterBuy,
                    levelSell: row.levelMostExpensiveQuarterProd
                };
                priceLevel = row.levelCheapestQuarterBuy;
                break;
            }
        } else {
            currentPrice = {
                buy: row.priceCZKhourBuy,
                sell: row.priceCZKhourProd,
                levelBuy: row.levelCheapestHourBuy,
                levelSell: row.levelMostExpensiveHourProd
            };
            priceLevel = row.levelCheapestHourBuy;
            break;
        }
    }
}

// Uložit do global kontextu
global.set("fve_current_price", currentPrice);
global.set("fve_price_level", priceLevel);
global.set("fve_prices_forecast", dedupedPrices);

msg.payload = {
    currentPrice: currentPrice,
    priceLevel: priceLevel,
    pricesCount: dedupedPrices.length,
    rawCount: prices.length,
    timestamp: now.toISOString()
};

const levelText = priceLevel <= 4 ? "levná" : (priceLevel >= 7 ? "drahá" : "střední");
node.status({fill: priceLevel <= 4 ? "green" : (priceLevel >= 7 ? "red" : "yellow"), shape:"dot", text: `Level ${priceLevel} (${levelText}) | ${dedupedPrices.length}/${prices.length} řádků`});

return msg;

// Sestavení aktuálního stavu systému
const config = global.get("fve_config") || {};
const priceLevel = global.get("fve_price_level") || 5;
const currentPrice = global.get("fve_current_price") || {};

const status = {
    timestamp: new Date().toISOString(),

    // Baterie
    battery_soc: msg.battery_soc || 0,
    battery_energy_kwh: (msg.battery_soc / 100) * (config.kapacita_baterie_kwh || 28),
    battery_available_kwh: Math.max(0, ((msg.battery_soc - (config.min_soc || 20)) / 100) * (config.kapacita_baterie_kwh || 28)),
    battery_free_kwh: ((100 - msg.battery_soc) / 100) * (config.kapacita_baterie_kwh || 28),

    // Ceny
    price_level: priceLevel,
    price_buy: currentPrice.buy || 0,
    price_sell: currentPrice.sell || 0,
    is_cheap: priceLevel <= (config.prah_levna_energie || 4),
    is_expensive: priceLevel >= (config.prah_draha_energie || 7),

    // Konfigurace
    automatizace_enabled: config.automatizace_enabled !== false,
    prodej_z_baterie_enabled: config.prodej_z_baterie_enabled === true,
    blokace_vybijeni: config.blokace_vybijeni === true,
    manual_mod: config.manual_mod || "auto"
};

// Uložit do global kontextu
global.set("fve_status", status);

msg.payload = status;

const socText = `SOC: ${status.battery_soc}% | Level: ${status.price_level}`;
node.status({fill: status.battery_soc > 50 ? "green" : (status.battery_soc > 20 ? "yellow" : "red"), shape:"dot", text: socText});

return msg;

// Zpracuj HA stavy — aktualizace fve_config z HA entity změn
const config=global.get("fve_config")||{};
const eid=msg.entity_id||"",val=msg.payload;
var modeMap={"🤖 Automaticky":"auto","🟢 Normální provoz":"normal","🟡 Šetřit baterii":"setrit","🔵 Nabíjet ze sítě":"nabijet_ze_site","🔴 Prodávat do sítě":"prodavat","🟣 Zákaz přetoků":"zakaz_pretoku"};
switch(eid){
case "input_number.fve_kapacita_baterie":config.kapacita_baterie_kwh=parseFloat(val)||28;break;
case "number.min_soc":config.min_soc=parseFloat(val)||20;break;
case "input_number.fve_amortizace_baterie":config.amortizace_baterie_czk_kwh=parseFloat(val)||1.0;break;
case "input_number.fve_max_feed_in":config.max_feed_in_w=parseFloat(val)||7600;break;
case "input_number.fve_max_spotreba_sit":config.max_spotreba_sit_w=parseFloat(val)||22000;global.set("max_spotreba_sit",config.max_spotreba_sit_w);break;
case "input_boolean.fve_automatizace":config.automatizace_enabled=(val==="on");break;
case "input_boolean.fve_prodej_z_baterie":config.prodej_z_baterie_enabled=(val==="on");break;
case "input_boolean.fve_blokace_vybijeni":config.blokace_vybijeni=(val==="on");break;
case "input_boolean.letni_rezim":config.letni_rezim=(val==="on");break;
case "input_number.predpoved_solarni_vyroby_dnes":config.forecast_vyroba_dnes=parseFloat(val)||0;global.set("forecast_vyroba_dnes",config.forecast_vyroba_dnes);break;
case "input_number.predpoved_solarni_vyroby_zitra":config.forecast_vyroba_zitra=parseFloat(val)||0;global.set("forecast_vyroba_zitra",config.forecast_vyroba_zitra);break;
case "input_number.zbyvajici_solarni_vyroba_dnes":config.zbyvajici_solar_dnes=parseFloat(val)||0;global.set("zbyvajici_solar_dnes",config.zbyvajici_solar_dnes);break;
case "sensor.energy_production_today_3":config.forecast_vyroba_dnes_om=parseFloat(val)||0;
if((config.solar_forecast_source||"VICTRON")==="OPEN_METEO"){config.forecast_vyroba_dnes=config.forecast_vyroba_dnes_om;global.set("forecast_vyroba_dnes",config.forecast_vyroba_dnes);}break;
case "sensor.energy_production_tomorrow_3":config.forecast_vyroba_zitra_om=parseFloat(val)||0;
if((config.solar_forecast_source||"VICTRON")==="OPEN_METEO"){config.forecast_vyroba_zitra=config.forecast_vyroba_zitra_om;global.set("forecast_vyroba_zitra",config.forecast_vyroba_zitra);}break;
case "sensor.energy_production_today_remaining_3":config.zbyvajici_solar_dnes_om=parseFloat(val)||0;
if((config.solar_forecast_source||"VICTRON")==="OPEN_METEO"){config.zbyvajici_solar_dnes=config.zbyvajici_solar_dnes_om;global.set("zbyvajici_solar_dnes",config.zbyvajici_solar_dnes);}break;
case "sensor.energy_current_hour_3":config.forecast_current_hour_kwh=parseFloat(val)||0;global.set("forecast_current_hour_kwh",config.forecast_current_hour_kwh);break;
case "input_select.fve_rezim_casu":config.rezim_casu=val;break;
case "input_number.fve_plan_extreme_low_solar_kwh":config.plan_extreme_low_solar_kwh=parseFloat(val)||5;break;
case "input_select.fve_manual_mod":config.manual_mod=modeMap[val]||val;break;}
global.set("fve_config",config);
msg.payload={entity_id:eid,value:val,config:config};
node.status({fill:"blue",shape:"dot",text:eid.split(".")[1]+": "+val});
return msg;
